8	import Foundation
9	import Combine
10	import SwiftUI
11	
12	final class SpeedometerViewModel: ObservableObject {
13	    
14	    @Published var currentValue: Float = 0.0
15	    @Published var range: ClosedRange<Float>
16	    
17	    private let queue: DispatchQueue
18	    private var timer: Timer?
19	    private var currentMaxValue: Float
20	    private var candidateMaxValue: Float?
21	    
22	    private var cancellable: Set<AnyCancellable> = .init()
23	    
24	    init(
25	        initialMaxValue: Float,
26	        averagingRawDataPublished: AnyPublisher<Float, Never>,
27	        queueLabel: String
28	    ) {
29	        self.queue = DispatchQueue(label: "com.radiacode.\(queueLabel).search")
30	        self.currentMaxValue = initialMaxValue
31	        self.range = 0.0...initialMaxValue
32	        
33	        averagingRawDataPublished
34	            .receive(on: queue)
35	            .sink { [weak self] value in
36	                guard let self = self else { return }
37	                if value > self.range.upperBound {
38	                    while value > self.currentMaxValue {
39	                        self.currentMaxValue *= 2
40	                    }
41	                    self.candidateMaxValue = nil
42	                    self.stopTimer()
43	                    Task { @MainActor in
44	                        self.range = 0.0...self.currentMaxValue
45	                    }
46	                } else if self.currentMaxValue != initialMaxValue, candidateMaxValue != initialMaxValue {
47	                    var shouldRecalculateMaxCount = self.candidateMaxValue == nil
48	                    if let candidateMaxValue, value < candidateMaxValue / 2 {
49	                        shouldRecalculateMaxCount = true
50	                    }
51	                    if shouldRecalculateMaxCount {
52	                        let maxCountRate = self.calculateReduceScale(
53	                            value: value,
54	                            initialValue: initialMaxValue,
55	                            maxValue: self.currentMaxValue
56	                        )
57	                        Task { @MainActor in
58	                            self.candidateMaxValue = maxCountRate
59	                            self.startTimer()
60	                        }
61	                    }
62	                }
63	                Task { @MainActor in
64	                    self.currentValue = value
65	                }
66	            }
67	            .store(in: &cancellable)
68	    }
69	    
70	    private func calculateReduceScale(value: Float, initialValue: Float, maxValue: Float) -> Float {
71	        if value <= initialValue {
72	            return initialValue
73	        }
74	        if value <= maxValue / 2 {
75	            return calculateReduceScale(value: value, initialValue: initialValue, maxValue: maxValue / 2)
76	        }
77	        return maxValue
78	    }
79	    
80	    private func stopTimer() {
81	        timer?.invalidate()
82	        timer = nil
83	    }
84	    
85	    @MainActor
86	    private func startTimer() {
87	        timer = Timer(once: 30) { [weak self] in
88	            guard let self = self, let candidateMaxValue else { return }
89	            currentMaxValue = candidateMaxValue
90	            self.candidateMaxValue = nil
91	            self.range = 0.0...self.currentMaxValue
92	        }
93	    }
94	}
95	
96	extension SpeedometerViewModel: Equatable {
97	    static func == (lhs: SpeedometerViewModel, rhs: SpeedometerViewModel) -> Bool {
98	        lhs.currentValue == rhs.currentValue &&
99	        lhs.range == rhs.range &&
100	        lhs.currentMaxValue == rhs.currentMaxValue &&
101	        lhs.candidateMaxValue == rhs.candidateMaxValue
102	    }
103	}
